function log(target: any,
  ctx: ClassMethodDecoratorContext) {
  return function (...args: any[]) {
    console.log(
      `${String(ctx.name)}(${args})`
    );
    return target.apply(this, args);
  };
}

class API {
  @log
  fetchUser(id: string) { /* ... */ }
}

function memo(target: any,
  ctx: ClassMethodDecoratorContext) {
  const cache = new Map();
  return function (...args: any[]) {
    const key = JSON.stringify(args);
    if (!cache.has(key))
      cache.set(key,
        target.apply(this, args));
    return cache.get(key);
  };
}

function sealed(
  target: Function,
  _ctx: ClassDecoratorContext
) {
  Object.seal(target);
  Object.seal(target.prototype);
}

@sealed
class Config {
  host = 'localhost';
  port = 3000;
}

function validate(target: any,
  ctx: ClassMethodDecoratorContext) {
  return function (...args: any[]) {
    for (const arg of args) {
      if (arg == null)
        throw new Error(
          `${String(ctx.name)}: null arg`
        );
    }
    return target.apply(this, args);
  };
}

function throttle(ms: number) {
  return (target: any,
    _ctx: ClassMethodDecoratorContext
  ) =&gt; {
    let last = 0;
    return function (...args: any[]) {
      if (Date.now() - last &lt; ms) return;
      last = Date.now();
      return target.apply(this, args);
    };
  };
}
